package be.schaubroeck.lpb.rkm.rekenmotor.util;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Vergoeding;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.Rekenwijze;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.rsz.RszConstants;
import com.google.common.collect.Sets;
import org.joda.time.LocalTime;

import java.util.Set;

public class CheckRegulTool {

    private static final Set<Rekenwijze> VERWACHTE_REKENWIJZE = Sets.immutableEnumSet(Rekenwijze.PRESTATIE, Rekenwijze.MAAND, Rekenwijze.UUR);

    public void checkRegulOpper(RekenTijd rekenTijd, Opper opper, RegulManager regulManager) {
        boolean beginVoorGrens = opper.getActualFrom().isBefore(RszConstants.START_DMFAPPL);
        boolean eindVoorGrens = opper.getActualTo().isBefore(RszConstants.START_DMFAPPL);
        if (beginVoorGrens && !eindVoorGrens && rekenTijd.rekenTijdstip
                .isAfter(RszConstants.START_DMFAPPL.toLocalDateTime(LocalTime.MIDNIGHT))) {
            regulManager.addRegul(rekenTijd.beginDatum, opper.getOpdracht(), Regulkode.SPLITS_OP_2005);
        } else if (eindVoorGrens && !(opper.getRszppo().getWerkgeversCategorie() == WerkgeversCategorie.NVT
                && opper.getRszppo().getWerknemersKengetal() == DmfapplWnkengetal.NVT)) {
            regulManager.addRegul(rekenTijd.beginDatum, opper.getOpdracht(), Regulkode.DMFAPPL_VOOR_2005);
        } else if ((eindVoorGrens && opper.getRszppo().getTijdperk().equals(AkeTijdperk.DMFAPPL.getCode())) || (!beginVoorGrens && opper.getRszppo()
                .getTijdperk().equals(AkeTijdperk.RSZPPO.getCode()))) {
            regulManager.addRegul(rekenTijd.beginDatum, opper.getOpdracht(), Regulkode.TP_ONGELDIG);
        } else {
            checkTijdperkVergoedingen(rekenTijd, opper, regulManager);
        }
        if (!VERWACHTE_REKENWIJZE.contains(opper.getWeddeBerekening().getRekenWijze())) {
            regulManager.addRegul(rekenTijd.beginDatum, opper.getOpdracht(), Regulkode.ONGELDIGE_REKENWIJZE);
        }
    }

    private void checkTijdperkVergoedingen(RekenTijd rekenTijd, Opper opper, RegulManager regulManager) {
        AkeTijdperk huidigTijdperk;
        if (rekenTijd.rekenTijdstip.isAfter(RszConstants.START_DMFAPPL.toLocalDateTime(LocalTime.MIDNIGHT))) {
            huidigTijdperk = RekenTools.getTijdperk(opper.getActualTo());
        } else {
            huidigTijdperk = AkeTijdperk.RSZPPO;
        }

        for (Vergoeding vergoeding : opper.getVergoedingen()) {
            AkeTijdperk tijdperk = AkeTijdperk.getByCode(vergoeding.getTijdperk());
            if (huidigTijdperk != tijdperk) {
                regulManager.addRegul(rekenTijd.beginDatum, opper.getOpdracht(), Regulkode.TP_ONGELDIG);
            }
        }
    }
}
